"""Медианный фильтр."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseFilter, _check_odd_window, _reflect_padclass MedianFilter(BaseFilter):    name = "Медианный фильтр"    description = "Скользящая медиана окна нечётной длины."    params_schema = {        "window_length": {"type": "int", "default": 5,                          "min": 1, "max": 10_001,                          "label": "Размер окна (нечётное)"},    }    def _filter(self, x: np.ndarray, p: dict, signal: Signal) -> np.ndarray:        w = int(p["window_length"])        _check_odd_window("window_length", w, x.size)        if w == 1:            return x.copy()        half = w // 2        padded = _reflect_pad(x, half)        from numpy.lib.stride_tricks import sliding_window_view        windows = sliding_window_view(padded, window_shape=w)        return np.median(windows, axis=1).astype(np.float64, copy=False)